// ==================================================
//  pages/Profile.jsx — بروفايل المستخدم
// ==================================================
import React, { useState, useEffect } from 'react'
import { getProfile } from '../services/authService'
import { getMyDesigns } from '../services/designService'

export default function Profile() {
  const [user, setUser]       = useState(null)
  const [designs, setDesigns] = useState([])
  const [loading, setLoading] = useState(true)
  const [editing, setEditing] = useState(false)
  const [form, setForm]       = useState({ username: '', phone: '' })
  const [saved, setSaved]     = useState(false)

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      const [userData, designsData] = await Promise.all([getProfile(), getMyDesigns()])
      setUser(userData)
      setDesigns(designsData)
      setForm({ username: userData.username, phone: userData.phone || '' })
    } catch {
      // بيانات تجريبية
      setUser({ username: 'أحمد', email: 'ahmed@gmail.com', phone: '', created_at: new Date().toISOString() })
      setDesigns([])
    } finally {
      setLoading(false)
    }
  }

  const handleSave = () => {
    // هنا تستدعي updateProfile(form)
    setUser(prev => ({ ...prev, ...form }))
    setEditing(false)
    setSaved(true)
    setTimeout(() => setSaved(false), 3000)
  }

  if (loading) return <div className="page-center"><div className="spinner" /></div>

  return (
    <div style={styles.page}>
      <div style={styles.layout}>

        {/* كارد البيانات */}
        <div style={styles.card}>
          {/* صورة المستخدم */}
          <div style={styles.avatarBox}>
            <div style={styles.avatar}>
              {user?.username?.[0]?.toUpperCase() || '👤'}
            </div>
          </div>

          {!editing ? (
            <>
              <h2 style={styles.name}>{user?.username}</h2>
              <p style={styles.email}>{user?.email}</p>
              {user?.phone && <p style={styles.phone}>📞 {user.phone}</p>}
              <p style={styles.joined}>
                انضم في: {new Date(user?.created_at).toLocaleDateString('ar-SA')}
              </p>

              {saved && <p className="msg-success" style={{textAlign:'center'}}>✅ تم الحفظ</p>}

              <button
                onClick={() => setEditing(true)}
                className="btn btn-outline"
                style={{ width: '100%', marginTop: 24 }}
              >
                ✏️ تعديل البيانات
              </button>
            </>
          ) : (
            <>
              <div style={styles.field}>
                <label style={styles.label}>اسم المستخدم</label>
                <input
                  value={form.username}
                  onChange={e => setForm({...form, username: e.target.value})}
                  className="input"
                />
              </div>
              <div style={styles.field}>
                <label style={styles.label}>رقم الجوال</label>
                <input
                  value={form.phone}
                  onChange={e => setForm({...form, phone: e.target.value})}
                  placeholder="05xxxxxxxx"
                  className="input"
                />
              </div>
              <div style={{ display: 'flex', gap: 10, marginTop: 16 }}>
                <button onClick={handleSave}           className="btn btn-primary" style={{flex:1}}>حفظ</button>
                <button onClick={() => setEditing(false)} className="btn btn-outline" style={{flex:1}}>إلغاء</button>
              </div>
            </>
          )}

          {/* إحصائيات */}
          <div style={styles.stats}>
            <div style={styles.stat}>
              <span style={styles.statNum}>{designs.length}</span>
              <span style={styles.statLabel}>تصميم</span>
            </div>
            <div style={styles.stat}>
              <span style={styles.statNum}>0</span>
              <span style={styles.statLabel}>طلب</span>
            </div>
            <div style={styles.stat}>
              <span style={styles.statNum}>0</span>
              <span style={styles.statLabel}>إعجاب</span>
            </div>
          </div>
        </div>

        {/* تصاميمي */}
        <div style={styles.designsSection}>
          <h2 style={styles.sectionTitle}>تصاميمي</h2>

          {designs.length === 0 ? (
            <div style={styles.empty}>
              <span style={{fontSize: 60}}>🎨</span>
              <p style={{color:'#aaa', marginTop:12}}>لم تضف أي تصميم بعد</p>
            </div>
          ) : (
            <div style={styles.designsGrid}>
              {designs.map(d => (
                <div key={d.id} style={styles.designCard}>
                  <div style={styles.designImg}>
                    {d.image ? (
                      <img src={d.image} alt={d.title} style={{width:'100%',height:'100%',objectFit:'cover'}} />
                    ) : (
                      <span style={{fontSize:40}}>👗</span>
                    )}
                  </div>
                  <div style={{padding:'12px 14px'}}>
                    <p style={styles.designTitle}>{d.title}</p>
                    <p style={styles.designPrice}>{d.price} ر.س</p>
                    <span style={{
                      fontSize:11, padding:'3px 10px', borderRadius:20,
                      background: d.status === 'published' ? '#e8f5e9' : '#fff8e1',
                      color: d.status === 'published' ? '#27ae60' : '#f39c12'
                    }}>
                      {d.status === 'published' ? 'منشور' : 'مسودة'}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

const styles = {
  page:          { padding: '48px 60px', maxWidth: 1100, margin: '0 auto' },
  layout:        { display: 'grid', gridTemplateColumns: '320px 1fr', gap: 32, alignItems: 'start' },
  card:          { background: '#fff', borderRadius: 20, padding: 32, boxShadow: '0 4px 20px rgba(0,0,0,0.07)' },
